import{_ as s,o as i,c as a,ae as l}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"커맨드 큐","description":"인바운드 자동 응답 실행을 직렬화하는 커맨드 큐 설계","frontmatter":{"title":"커맨드 큐","description":"인바운드 자동 응답 실행을 직렬화하는 커맨드 큐 설계"},"headers":[],"relativePath":"concepts/queue.md","filePath":"concepts/queue.md","lastUpdated":null}'),o={name:"concepts/queue.md"};function t(n,e,d,c,h,p){return i(),a("div",null,[...e[0]||(e[0]=[l(`<h1 id="커맨드-큐-2026-01-16" tabindex="-1">커맨드 큐 (2026-01-16) <a class="header-anchor" href="#커맨드-큐-2026-01-16" aria-label="Permalink to &quot;커맨드 큐 (2026-01-16)&quot;">​</a></h1><p>여러 에이전트 실행이 충돌하는 것을 방지하면서도 세션 간 안전한 병렬성을 허용하기 위해 인바운드 자동 응답 실행 (모든 채널)을 작은 프로세스 내 큐를 통해 직렬화합니다.</p><h2 id="이유" tabindex="-1">이유 <a class="header-anchor" href="#이유" aria-label="Permalink to &quot;이유&quot;">​</a></h2><ul><li>자동 응답 실행은 비용이 많이 들고 (LLM 호출) 여러 인바운드 메시지가 가까운 시간에 도착하면 충돌할 수 있습니다.</li><li>직렬화는 공유 리소스 (세션 파일, 로그, CLI stdin) 경쟁을 피하고 업스트림 속도 제한 가능성을 줄입니다.</li></ul><h2 id="작동-방식" tabindex="-1">작동 방식 <a class="header-anchor" href="#작동-방식" aria-label="Permalink to &quot;작동 방식&quot;">​</a></h2><ul><li>레인 인식 FIFO 큐는 구성 가능한 동시성 상한 (구성되지 않은 레인의 기본값 1; main 기본값 4, subagent 기본값 8)으로 각 레인을 드레인합니다.</li><li><code>runEmbeddedPiAgent</code>는 <strong>세션 키</strong> (레인 <code>session:&lt;key&gt;</code>)로 큐에 넣어 세션당 하나의 활성 실행만 보장합니다.</li><li>각 세션 실행은 전체 병렬성이 <code>agents.defaults.maxConcurrent</code>로 제한되도록 <strong>전역 레인</strong> (기본값 <code>main</code>)에 큐에 넣어집니다.</li><li>상세 로깅이 활성화된 경우, 큐에 넣어진 실행이 시작 전에 ~2초 이상 대기했다면 짧은 알림을 내보냅니다.</li><li>타이핑 표시기는 큐에 넣을 때 즉시 실행됩니다 (채널이 지원하는 경우). 따라서 차례를 기다리는 동안 사용자 경험은 변경되지 않습니다.</li></ul><h2 id="큐-모드-채널별" tabindex="-1">큐 모드 (채널별) <a class="header-anchor" href="#큐-모드-채널별" aria-label="Permalink to &quot;큐 모드 (채널별)&quot;">​</a></h2><p>인바운드 메시지는 현재 실행을 조종하거나, 후속 턴을 기다리거나, 둘 다 할 수 있습니다:</p><ul><li><code>steer</code>: 즉시 현재 실행에 주입합니다 (다음 도구 경계 후 보류 중인 도구 호출 취소). 스트리밍이 아닌 경우, followup으로 폴백합니다.</li><li><code>followup</code>: 현재 실행이 끝난 후 다음 에이전트 턴에 큐에 넣습니다.</li><li><code>collect</code>: 큐에 넣어진 모든 메시지를 <strong>단일</strong> followup 턴으로 통합합니다 (기본값). 메시지가 다른 채널/스레드를 대상으로 하면 라우팅을 보존하기 위해 개별적으로 드레인합니다.</li><li><code>steer-backlog</code> (별칭 <code>steer+backlog</code>): 지금 조종 <strong>하고</strong> 후속 턴을 위해 메시지를 보존합니다.</li><li><code>interrupt</code> (레거시): 해당 세션의 활성 실행을 중단한 다음 최신 메시지를 실행합니다.</li><li><code>queue</code> (레거시 별칭): <code>steer</code>와 동일합니다.</li></ul><p>Steer-backlog는 조종된 실행 후 후속 응답을 받을 수 있으므로, 스트리밍 표면에서 중복처럼 보일 수 있습니다. 인바운드 메시지당 하나의 응답을 원하면 <code>collect</code>/<code>steer</code>를 사용하십시오.</p><p><code>/queue collect</code>를 독립 실행형 커맨드로 보내거나 (세션별) <code>messages.queue.byChannel.discord: &quot;collect&quot;</code>를 설정하십시오.</p><p>기본값 (구성에서 설정되지 않은 경우):</p><ul><li>모든 표면 → <code>collect</code></li></ul><p><code>messages.queue</code>를 통해 전역 또는 채널별로 구성하십시오:</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  messages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    queue</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;collect&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      debounceMs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      cap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      drop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;summarize&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      byChannel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">discord</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;collect&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="큐-옵션" tabindex="-1">큐 옵션 <a class="header-anchor" href="#큐-옵션" aria-label="Permalink to &quot;큐 옵션&quot;">​</a></h2><p>옵션은 <code>followup</code>, <code>collect</code>, <code>steer-backlog</code> (그리고 followup으로 폴백될 때 <code>steer</code>)에 적용됩니다:</p><ul><li><code>debounceMs</code>: followup 턴을 시작하기 전에 조용해질 때까지 기다립니다 (&quot;계속, 계속&quot; 방지).</li><li><code>cap</code>: 세션당 최대 큐에 넣어진 메시지 수.</li><li><code>drop</code>: 오버플로 정책 (<code>old</code>, <code>new</code>, <code>summarize</code>).</li></ul><p>Summarize는 삭제된 메시지의 짧은 목록을 유지하고 합성 followup 프롬프트로 주입합니다. 기본값: <code>debounceMs: 1000</code>, <code>cap: 20</code>, <code>drop: summarize</code>.</p><h2 id="세션별-오버라이드" tabindex="-1">세션별 오버라이드 <a class="header-anchor" href="#세션별-오버라이드" aria-label="Permalink to &quot;세션별 오버라이드&quot;">​</a></h2><ul><li><code>/queue &lt;mode&gt;</code>를 독립 실행형 커맨드로 보내어 현재 세션의 모드를 저장하십시오.</li><li>옵션을 결합할 수 있습니다: <code>/queue collect debounce:2s cap:25 drop:summarize</code></li><li><code>/queue default</code> 또는 <code>/queue reset</code>은 세션 오버라이드를 지웁니다.</li></ul><h2 id="범위-및-보장" tabindex="-1">범위 및 보장 <a class="header-anchor" href="#범위-및-보장" aria-label="Permalink to &quot;범위 및 보장&quot;">​</a></h2><ul><li>게이트웨이 응답 파이프라인을 사용하는 모든 인바운드 채널 (WhatsApp web, Telegram, Slack, Discord, Signal, iMessage, webchat 등)의 자동 응답 에이전트 실행에 적용됩니다.</li><li>기본 레인 (<code>main</code>)은 인바운드 + 메인 하트비트에 대한 프로세스 전체입니다. 세션을 병렬로 허용하려면 <code>agents.defaults.maxConcurrent</code>를 설정하십시오.</li><li>백그라운드 작업이 인바운드 응답을 차단하지 않고 병렬로 실행될 수 있도록 추가 레인 (예: <code>cron</code>, <code>subagent</code>)이 존재할 수 있습니다. 이 분리된 실행은 <a href="/openclaw-docs-ko/automation/tasks">백그라운드 태스크</a>로 추적됩니다.</li><li>세션별 레인은 한 번에 하나의 에이전트 실행만 주어진 세션을 건드리도록 보장합니다.</li><li>외부 종속성 또는 백그라운드 워커 스레드 없음. 순수 TypeScript + 프로미스.</li></ul><h2 id="트러블슈팅" tabindex="-1">트러블슈팅 <a class="header-anchor" href="#트러블슈팅" aria-label="Permalink to &quot;트러블슈팅&quot;">​</a></h2><ul><li>커맨드가 막힌 것처럼 보이면 상세 로그를 활성화하고 &quot;queued for …ms&quot; 줄을 찾아 큐가 드레인되고 있는지 확인하십시오.</li><li>큐 깊이가 필요하면 상세 로그를 활성화하고 큐 타이밍 줄을 관찰하십시오.</li></ul>`,25)])])}const u=s(o,[["render",t]]);export{k as __pageData,u as default};
